def score(item: int, bins: np.ndarray) -> np.ndarray:
    half = (bins.max() + 1) // 2  # approximate capacity / 2
    if item > half:
        # Large item: prefer worst-fit (largest residual) to avoid opening new bins
        return bins
    else:
        # Small/medium item: prefer best-fit (smallest residual >= item)
        # Invert so that smaller residual gets higher score
        max_cap = bins.max()
        return max_cap - bins

def score(item: int, bins: np.ndarray) -> np.ndarray:
    if len(bins) == 0:
        return np.array([], dtype=float)
    residuals = bins - item
    # Sinusoidal preference for residuals that are multiples of item
    oscillation = np.cos(2 * np.pi * residuals / (item + 1e-10))
    # Exponential penalty for large residuals
    waste_penalty = np.exp(-residuals / (item + 1))
    scores = oscillation + waste_penalty
    return scores

def score(item: int, bins: np.ndarray) -> np.ndarray:
    residual = bins - item
    return - (residual ** 2) + (residual * 0.01)
